# WebSocket server setup
from machine import Pin
import usocket as socket

led = Pin(2, Pin.OUT)  # Example pin for an LED

def serve_forever():
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.bind(('0.0.0.0', 80))
    s.listen(5)

    while True:
        conn, addr = s.accept()
        print('Got a connection from %s' % str(addr))
        request = conn.recv(1024)
        print("Request Content = %s" % str(request))

        response = "HTTP/1.1 200 OK\n"
        response += "Content-Type: text/html\n\n"
        response += "<html><body><h1>Welcome to ESP32 WebSocket Server</h1></body></html>"

        conn.send(response)
        conn.close()

serve_forever()